mapper.select:
SELECT v.database_id AS databaseId, v.table_name AS tableName, MAX(v.last_vacuum) AS lastVacuum, MAX(v.last_autovacuum) AS lastAutovacuum, AVG(v.n_dead_tup) AS deadTuples, AVG(v.n_mod_since_analyze) AS modSinceAnalyze, AVG(v.bloat_ratio) AS bloatRatio, COUNT(CASE WHEN v.session_trigger = 'manual' AND v.collected_at >= NOW() - INTERVAL '24 hours' THEN 1 END) AS vacuumCount24h, COUNT(CASE WHEN v.session_trigger = 'autovacuum' AND v.collected_at >= NOW() - INTERVAL '24 hours' THEN 1 END) AS autovacuumCount24h FROM vacuum_raw_metrics v WHERE v.collected_at BETWEEN #{start} AND #{end}
AND v.database_id = #{databaseId, jdbcType=BIGINT}
-- 완료된 세션이나 실행 중인 세션 또는 일반 메트릭 포함 AND (v.session_phase = 'completed' OR v.session_phase != 'not_running' OR v.session_phase IS NULL) GROUP BY v.database_id, v.table_name ORDER BY GREATEST(MAX(v.last_vacuum), MAX(v.last_autovacuum)) DESC NULLS LAST LIMIT 100
